frappe.ui.form.on("Delear Registration", {

    send_otp(frm) {

        if (!frm.doc.gst_no) {
            frappe.msgprint("❌ Please enter GST Number");
            return;
        }

        frappe.call({
            method: "shoption_api.dealer.gst_api.send_gst_otp",
            args: {
                gst_number: frm.doc.gst_no
            },
            // args: {
            //     mobile_no: frm.doc.mobile_number,
            //     gst_number: frm.doc.gst_no
            // },
            callback: function(r) {

                console.log("SEND OTP Response:", r);

                if (!r.message) {
                    frappe.msgprint("❌ No response from API");
                    return;
                }

                if (r.message.status === true) {
                    frappe.msgprint("✅ OTP Sent Successfully");
                } else {
                    frappe.msgprint("❌ Invalid GST ");
                }
            }
        });
    },

    verify(frm) {

        if (!frm.doc.enter_otp) {
            frappe.msgprint("❌ Please enter OTP");
            return;
        }
        frappe.call({
            method: "shoption_api.dealer.gst_api.send_gst_otp",
            args: {
                gst_number: frm.doc.gst_no
            },
            callback: function(r) {
                if (r.message) {
                    if (r.message.status) {
                        frm.set_value("client_id", r.message.client_id);
                        frappe.msgprint("OTP Sent Successfully");
                    } else {
                        frappe.msgprint("Invalid GST");
                    }
                }
            }
        });

    }
});

frappe.ui.form.on("Delear Registration", {
    onload(frm) {
        // Get lead ID from URL
        const url = new URL(window.location.href);
        const lead_id = url.searchParams.get("from_lead");

        if (!lead_id) return;

        // Set lead reference
        frm.set_value("from_document", lead_id);

        // Fetch Lead details
        frappe.call({
            method: "frappe.client.get",
            args: {
                doctype: "Lead",
                name: lead_id
            },
            callback: function(r) {
                if (!r.message) return;

                const lead = r.message;

                // Auto-fill fields
                frm.set_value("mobile_number", lead.mobile_no);
                frm.set_value("party_name", lead.lead_name);
                frm.set_value("email_id", lead.email_id);
            }
        });
    }
});

