    after_save(frm) {
        // if already submitted, no need to submit again
        if (frm.doc.docstatus === 1) return;

        // auto-submit only when form is freshly saved
        frappe.call({
            method: "frappe.client.submit",
            args: {
                doctype: frm.doc.doctype,
                name: frm.doc.name
            },
            callback: function() {
                frappe.show_alert({
                    message: "Farmer Registration Submitted Automatically",
                    indicator: "green"
                });
                frm.reload_doc();
            }
        });
    }
});

