    custom_full_payment_discount_type: calculate_prices,
    custom_full_payment_discount_value: calculate_prices,

    custom_cod_discount_type: calculate_prices,
    custom_cod_discount_value: calculate_prices,

    custom_diplay_rate_type: calculate_prices,
    custom_display_rate_discount: calculate_prices,

    price_list_rate: calculate_prices,
    rate: calculate_prices
});

function calculate_prices(frm) {
    let rate = frm.doc.rate || frm.doc.price_list_rate || 0;

    // --------------------------
    // FULL PAYMENT (UNCHANGED)
    // --------------------------
    if (frm.doc.custom_full_payment_discount_type === "Percentage") {
        let d = frm.doc.custom_full_payment_discount_value || 0;
        frm.doc.custom_full_payment = rate - (rate * d / 100);
    }
    else if (frm.doc.custom_full_payment_discount_type === "Amount") {
        let d = frm.doc.custom_full_payment_discount_value || 0;
        frm.doc.custom_full_payment = rate - d;
    }
    else {
        frm.doc.custom_full_payment = rate;
    }

    // --------------------------
    // DISPLAY RATE (UNCHANGED)
    // --------------------------
    if (frm.doc.custom_diplay_rate_type === "Percentage") {
        let d = frm.doc.custom_display_rate_discount || 0;
        frm.doc.custom_cod_display_rate = rate - (rate * d / 100);
    }
    else if (frm.doc.custom_diplay_rate_type === "Amount") {
        let d = frm.doc.custom_display_rate_discount || 0;
        frm.doc.custom_cod_display_rate = rate - d;
    }
    else {
        frm.doc.custom_cod_display_rate = rate;
    }

    // --------------------------
    // COD PRICE (UPDATED LOGIC ONLY)
    // Cash On Delivery Price =
    // rate - COD Discount Value - COD Display Rate
    // --------------------------
    let cod_discount = frm.doc.custom_cod_discount_value || 0;
    let cod_display_rate = frm.doc.custom_cod_display_rate || 0;

    frm.doc.custom_cash_on_delivery_ =
        rate - cod_discount - cod_display_rate;

    frm.refresh_fields();
}

