frappe.ui.form.on("Dealership Profile", {
    refresh(frm) {
        console.log("🔥 Dealership Profile refreshed");

        // Safety checks
        if (!frm.doc.dealership_plan) {
            console.log("❌ No dealership_plan");
            return;
        }

        // Avoid duplicate refill
        if (frm.doc.dealership_plan_range && frm.doc.dealership_plan_range.length > 0) {
            console.log("ℹ️ Plan range already filled");
            return;
        }

        console.log("✅ Fetching plan range for:", frm.doc.dealership_plan);

        frappe.call({
            method: "shoption_api.dealership.dealership_profile.get_dealership_plan_range",
            args: {
                dealership_plan: frm.doc.dealership_plan
            },
            callback(r) {
                console.log("📦 Response:", r.message);

                if (!r.message || r.message.length === 0) {
                    console.log("❌ No rows returned");
                    return;
                }

                frm.clear_table("dealership_plan_range");

                r.message.forEach(row => {
                    let d = frm.add_child("dealership_plan_range");
                    d.notation = row.notation;
                    d.value = row.value;
                    d.in__percentage = row.in__percentage;
                });

                frm.refresh_field("dealership_plan_range");
                console.log("✅ Plan range filled successfully");
            }
        });
    }
});

frappe.ui.form.on('Material Request', {
    custom_view_last_purchase: function(frm) {

        if (!frm.doc.items || frm.doc.items.length === 0) {
            frappe.msgprint("No items found in this Material Request");
            return;
        }

        frappe.call({
            method: "get_last_purchase_info_for_mr",
            args: {
                material_request: frm.doc.name
            },
            callback: function(r) {

                if (!r.message || r.message.length === 0) {
                    frappe.msgprint("No previous purchase data found for any item");
                    return;
                }

                let message = ``;

                r.message.forEach((row, idx) => {

                    const collapse_id = `lp_details_${idx}`;

                    /* ===============================
                       COLLAPSIBLE ITEM CARD
                    ================================*/
                    message += `
                        <div style="border:1px solid #444; border-radius:8px; margin-bottom:16px; overflow:hidden">

                            <!-- HEADER (CLICKABLE) -->
                            <div 
                                style="padding:12px; cursor:pointer; background:#1f1f1f"
                                onclick="
                                    const el = document.getElementById('${collapse_id}');
                                    el.style.display = el.style.display === 'none' ? 'block' : 'none';
                                "
                            >
                                <div><b>Item:</b> ${row.item_code} – ${row.item_name || ""}</div>
                                <div><b>Supplier:</b> ${row.supplier || "N/A"} - ${row.supplier_name || ""}</div>
                                <div><b>Purchase Date:</b> ${row.posting_date || "N/A"}</div>
                            </div>

                            <!-- COLLAPSIBLE BODY -->
                            <div id="${collapse_id}" style="display:none; padding:12px; background:#141414">

                                <div style="margin-bottom:10px">
                                    <b>Payment Terms:</b> ${row.payment_terms_template || "Not Defined"}
                                </div>
                    `;

                    /* ===============================
                       PAYMENT SCHEDULE TABLE
                    ================================*/
                    if (row.payment_schedule && row.payment_schedule.length) {
                        message += `
                            <div>
                                <b>Payment Schedule</b>
                                <table class="table table-bordered table-sm" style="margin-top:6px">
                                    <thead>
                                        <tr>
                                            <th>Payment Term</th>
                                            <th>Due Date</th>
                                            <th>Invoice Portion (%)</th>
                                            <th>Amount</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                        `;

                        row.payment_schedule.forEach(ps => {
                            message += `
                                <tr>
                                    <td>${ps.payment_term || ""}</td>
                                    <td>${ps.due_date || ""}</td>
                                    <td>${ps.invoice_portion || ""}</td>
                                    <td>${ps.payment_amount || ""}</td>
                                </tr>
                            `;
                        });

                        message += `
                                    </tbody>
                                </table>
                            </div>
                        `;
                    }

                    message += `
                            </div>
                        </div>
                    `;
                });

                frappe.msgprint({
                    title: "Last Purchase Details",
                    indicator: "blue",
                    message: message
                });
            }
        });
    }
});

