    }
});

async function filter_suppliers_by_items(frm) {

    if (!frm.doc.items || frm.doc.items.length === 0) {
        return;
    }

    let item_codes = frm.doc.items
        .map(row => row.item_code)
        .filter(Boolean);

    if (!item_codes.length) return;

    let supplier_sets = [];

    for (let item_code of item_codes) {

        let item_doc = await frappe.db.get_doc("Item", item_code);

        if (
            item_doc.custom_item_supplier &&
            item_doc.custom_item_supplier.length
        ) {
            // supplier_id is Supplier.name
            let supplier_ids = item_doc.custom_item_supplier.map(
                row => row.supplier_id
            );

            supplier_sets.push(new Set(supplier_ids));
        }
    }

    if (!supplier_sets.length) {
        return;
    }

    // UNION of all suppliers (same as your current logic)
    let allowed_suppliers = new Set(
        supplier_sets.flatMap(set => Array.from(set))
    );

    // Apply filter on Supplier field
    frm.set_query("supplier", function () {
        return {
            filters: {
                name: ["in", Array.from(allowed_suppliers)]
            }
        };
    });

    // Safety: clear supplier if not allowed
    if (
        frm.doc.supplier &&
        !allowed_suppliers.has(frm.doc.supplier)
    ) {
        frm.set_value("supplier", null);
    }
}

