function recalc_payment_schedule(frm) {

    let pi_date = frm.doc.custom_pi_date;
    let lr_date = frm.doc.custom_lr_date;

    if (!frm.doc.payment_schedule || !frm.doc.payment_schedule.length) {
        return;
    }

    let updated = false;

    frm.doc.payment_schedule.forEach(row => {

        // --- PI ---
        if (row.payment_term === "Some 10% Against PI" && pi_date) {
            row.due_date = pi_date;
            row.credit_days = 0;
            updated = true;
        }

        // --- Dispatch LR ---
        else if (row.payment_term === "Some 10% Against Dispatch LR" && lr_date) {
            row.due_date = lr_date;
            row.credit_days = 0;
            updated = true;
        }

        // --- GRN (LR + 1) ---
        else if (row.payment_term === "Some 10% Against GRN" && lr_date) {
            row.due_date = frappe.datetime.add_days(lr_date, 1);
            row.credit_days = 0;
            updated = true;
        }

        // --- 60% Credit (LR + 2) ---
        else if (row.payment_term === "Some 60% Credit Of Days" && lr_date) {
            row.due_date = frappe.datetime.add_days(lr_date, 2);
            row.credit_days = 0;
            updated = true;
        }
    });

    if (updated) {
        frm.refresh_field("payment_schedule");
        frm.set_dirty();   // mark change but NO server overwrite
    }
}

