async function open_outward_dialog(listview, invoices) {

    // 🔥 STEP 1: Fetch box data
    let preview = await frappe.call({
        method: "warrior.public.sales_invoice_hooks.get_no_of_boxes",
        args: {
            invoices: invoices.map(i => i.name)
        }
    });

    let data = preview.message || {
        total_boxes: 0,
        invoices: []
    };

    console.log("BOX DATA:", data);

    // 🔥 STEP 2: Dialog
    let d = new frappe.ui.Dialog({
        title: 'Create Outward',
        fields: [
            {
                fieldtype: 'Data',
                label: 'Material Handover',
                fieldname: 'material_handover',
                reqd: 1
            },
            {
                fieldtype: 'Attach',
                label: 'Photo',
                fieldname: 'photo'
            },
            {
                fieldtype: 'Int',
                label: 'No of Boxes',
                fieldname: 'total_boxes',
                default: data.total_boxes
            },
            {
                fieldtype: 'HTML',
                fieldname: 'invoice_preview'
            }
        ],

        primary_action: async function (values) {

            await frappe.call({
                method: "warrior.public.sales_invoice_hooks.create_outward",
                args: {
                    values: {
                        material_handover: values.material_handover,
                        photo: values.photo,
                        total_boxes: values.total_boxes,
                        invoices: invoices.map(i => i.name)
                    }
                }
            });

            frappe.msgprint("Outward Created");

            d.hide();

            // ✅ BEST: Refresh list view
            listview.refresh();

            // ✅ OPTIONAL: Full reload (use only if needed)
            // window.location.reload();
        }
    });

    d.show();

    // 🔥 STEP 3: Preview table
    let html = `
        <table class="table table-bordered table-sm">
            <tr>
                <th>Invoice</th>
                <th>Customer</th>
                <th>Boxes</th>
            </tr>
    `;

    (data.invoices || []).forEach(i => {
        html += `
            <tr>
                <td>${i.invoice}</td>
                <td>${i.customer}</td>
                <td><b>${i.boxes}</b></td>
            </tr>
        `;
    });

    html += `</table>`;

    d.fields_dict.invoice_preview.$wrapper.html(html);
}
